ROOT CAUSE: `server.listen()` is asynchronous; bind errors are emitted as an `'error'` event on the server, not thrown synchronously. Because no `'error'` handler is attached, Node.js treats it as an unhandled `EventEmitter` error and throws it to the process, killing everything.

FIX:

```ts
// streaming/sse-server.ts
import http from "node:http";
import { logger } from "../logger.js";

export function startSseServer(
  taskStore: TaskStore,
  port: number = parseInt(process.env["SSE_PORT"] ?? "3001", 10),
  host: string = process.env["SSE_HOST"] ?? "127.0.0.1",
): Promise<http.Server | null> {
  return new Promise((resolve) => {
    const server = http.createServer((req, res) => {
      // ... routes ...
    });

    server.once("error", (err: NodeJS.ErrnoException) => {
      logger.warn(
        { host, port, code: err.code, message: err.message },
        "SSE server failed to bind — task streaming unavailable; stdio MCP server continues",
      );
      resolve(null);          // caller gets null → SSE simply absent
    });

    server.listen(port, host, () => {
      logger.info({ host, port }, "SSE server listening");
      resolve(server);
    });
  });
}
```

