import { drizzle } from "drizzle-orm/better-sqlite3";
import * as schema from "./schema.js";
import { resolvedPath } from "./path.js"; // however you resolve it today

export const sqlite = new Database(resolvedPath);
sqlite.pragma("journal_mode = WAL");
sqlite.pragma("foreign_keys = ON");
export const db = drizzle(sqlite, { schema });
```

```ts
// db/migrate.ts
import { migrate } from "drizzle-orm/better-sqlite3/migrator";
import { db, sqlite } from "./client.js";

export function runMigrations(): void {
    // Must be outside any transaction — see SQLite docs on PRAGMA foreign_keys.
    sqlite.pragma("foreign_keys = OFF");
    try {
        migrate(db, {
            migrationsFolder: new URL("../../drizzle", import.meta.url).pathname,
        });
    } finally {
        sqlite.pragma("foreign_keys = ON");
    }
}
```

This is the preferred form: no casting, no reliance on Drizzle internals, and the raw handle is already available because we created it.

