describe("migration 0005 – task_events rows survive the tasks table rebuild", () => {
    it("does NOT delete task_events rows when making session_id nullable", () => {
        const { sqlite, db } = buildDb();

        // Run all migrations up to and including 0004 to establish baseline.
        // (In practice: run only the migrations before 0005, or seed manually.)
        // For this test we seed the pre-0005 schema by hand to keep it self-contained.
        sqlite.exec(`
            CREATE TABLE tasks (
                id TEXT PRIMARY KEY NOT NULL,
                session_id TEXT NOT NULL
            );
            CREATE TABLE task_events (
                id   TEXT PRIMARY KEY NOT NULL,
                task_id TEXT NOT NULL REFERENCES tasks(id) ON DELETE CASCADE
            );
            INSERT INTO tasks   VALUES ('t1', 's1');
            INSERT INTO task_events VALUES ('e1', 't1');
        `);

        // Verify precondition
        const before = sqlite.prepare("SELECT COUNT(*) as n FROM task_events").get() as { n: number };
        expect(before.n).toBe(1);

        // ---- BUGGY path (no pragma guard): simulate what the migrator does ----
        // Uncomment to see the test FAIL (demonstrating the bug):
        //
        // sqlite.transaction(() => {
        //     sqlite.exec(`
