        //         CREATE TABLE __new_tasks (id TEXT PRIMARY KEY NOT NULL, session_id TEXT);
        //         INSERT INTO __new_tasks SELECT id, session_id FROM tasks;
        //         DROP TABLE tasks;
        //         ALTER TABLE __new_tasks RENAME TO tasks;
        //         PRAGMA foreign_keys=ON;
        //     `);
        // })();

        // ---- FIXED path: disable FK enforcement OUTSIDE the transaction ----
        sqlite.pragma("foreign_keys = OFF");
        try {
            sqlite.transaction(() => {
                sqlite.exec(`
                    PRAGMA foreign_keys=OFF;
                    CREATE TABLE __new_tasks (id TEXT PRIMARY KEY NOT NULL, session_id TEXT);
                    INSERT INTO __new_tasks SELECT id, session_id FROM tasks;
                    DROP TABLE tasks;
                    ALTER TABLE __new_tasks RENAME TO tasks;
